import{_ as e,o as a,c as n,ai as p}from"./chunks/framework.CsYGeNYI.js";const h=JSON.parse('{"title":"OpenProse","description":"","frontmatter":{"summary":"OpenProse: .prose workflows, slash commands, and state in OpenSoul","read_when":["You want to run or write .prose workflows","You want to enable the OpenProse plugin","You need to understand state storage"],"title":"OpenProse"},"headers":[],"relativePath":"prose.md","filePath":"prose.md","lastUpdated":null}'),l={name:"prose.md"};function r(i,s,t,o,c,d){return a(),n("div",null,[...s[0]||(s[0]=[p(`<h1 id="openprose" tabindex="-1"><a class="header-anchor" href="#openprose">#</a> OpenProse</h1><p>OpenProse is a portable, markdown-first workflow format for orchestrating AI sessions. In OpenSoul it ships as a plugin that installs an OpenProse skill pack plus a <code>/prose</code> slash command. Programs live in <code>.prose</code> files and can spawn multiple sub-agents with explicit control flow.</p><p>Official site: <a href="https://www.prose.md" target="_blank" rel="noreferrer">https://www.prose.md</a></p><h2 id="what-it-can-do" tabindex="-1"><a class="header-anchor" href="#what-it-can-do">#</a> What it can do</h2><ul><li>Multi-agent research + synthesis with explicit parallelism.</li><li>Repeatable approval-safe workflows (code review, incident triage, content pipelines).</li><li>Reusable <code>.prose</code> programs you can run across supported agent runtimes.</li></ul><h2 id="install-enable" tabindex="-1"><a class="header-anchor" href="#install-enable">#</a> Install + enable</h2><p>Bundled plugins are disabled by default. Enable OpenProse:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> plugins</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> open-prose</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Restart the Gateway after enabling the plugin.</p><p>Dev/local checkout: <code>opensoul plugins install ./extensions/open-prose</code></p><p>Related docs: <a href="/docs/tools/plugin">Plugins</a>, <a href="/docs/plugins/manifest">Plugin manifest</a>, <a href="/docs/tools/skills">Skills</a>.</p><h2 id="slash-command" tabindex="-1"><a class="header-anchor" href="#slash-command">#</a> Slash command</h2><p>OpenProse registers <code>/prose</code> as a user-invocable skill command. It routes to the OpenProse VM instructions and uses OpenSoul tools under the hood.</p><p>Common commands:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/prose help</span></span>
<span class="line"><span>/prose run &lt;file.prose&gt;</span></span>
<span class="line"><span>/prose run &lt;handle/slug&gt;</span></span>
<span class="line"><span>/prose run &lt;https://example.com/file.prose&gt;</span></span>
<span class="line"><span>/prose compile &lt;file.prose&gt;</span></span>
<span class="line"><span>/prose examples</span></span>
<span class="line"><span>/prose update</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="example-a-simple-prose-file" tabindex="-1"><a class="header-anchor" href="#example-a-simple-prose-file">#</a> Example: a simple <code>.prose</code> file</h2><div class="language-prose vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">prose</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Research + synthesis with two agents running in parallel.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>input topic: &quot;What should we research?&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>agent researcher:</span></span>
<span class="line"><span>  model: sonnet</span></span>
<span class="line"><span>  prompt: &quot;You research thoroughly and cite sources.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>agent writer:</span></span>
<span class="line"><span>  model: opus</span></span>
<span class="line"><span>  prompt: &quot;You write a concise summary.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>parallel:</span></span>
<span class="line"><span>  findings = session: researcher</span></span>
<span class="line"><span>    prompt: &quot;Research {topic}.&quot;</span></span>
<span class="line"><span>  draft = session: writer</span></span>
<span class="line"><span>    prompt: &quot;Summarize {topic}.&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>session &quot;Merge the findings + draft into a final answer.&quot;</span></span>
<span class="line"><span>context: { findings, draft }</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="file-locations" tabindex="-1"><a class="header-anchor" href="#file-locations">#</a> File locations</h2><p>OpenProse keeps state under <code>.prose/</code> in your workspace:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.prose/</span></span>
<span class="line"><span>├── .env</span></span>
<span class="line"><span>├── runs/</span></span>
<span class="line"><span>│   └── {YYYYMMDD}-{HHMMSS}-{random}/</span></span>
<span class="line"><span>│       ├── program.prose</span></span>
<span class="line"><span>│       ├── state.md</span></span>
<span class="line"><span>│       ├── bindings/</span></span>
<span class="line"><span>│       └── agents/</span></span>
<span class="line"><span>└── agents/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>User-level persistent agents live at:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>~/.prose/agents/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="state-modes" tabindex="-1"><a class="header-anchor" href="#state-modes">#</a> State modes</h2><p>OpenProse supports multiple state backends:</p><ul><li><strong>filesystem</strong> (default): <code>.prose/runs/...</code></li><li><strong>in-context</strong>: transient, for small programs</li><li><strong>sqlite</strong> (experimental): requires <code>sqlite3</code> binary</li><li><strong>postgres</strong> (experimental): requires <code>psql</code> and a connection string</li></ul><p>Notes:</p><ul><li>sqlite/postgres are opt-in and experimental.</li><li>postgres credentials flow into subagent logs; use a dedicated, least-privileged DB.</li></ul><h2 id="remote-programs" tabindex="-1"><a class="header-anchor" href="#remote-programs">#</a> Remote programs</h2><p><code>/prose run &lt;handle/slug&gt;</code> resolves to <code>https://p.prose.md/&lt;handle&gt;/&lt;slug&gt;</code>. Direct URLs are fetched as-is. This uses the <code>web_fetch</code> tool (or <code>exec</code> for POST).</p><h2 id="opensoul-runtime-mapping" tabindex="-1"><a class="header-anchor" href="#opensoul-runtime-mapping">#</a> OpenSoul runtime mapping</h2><p>OpenProse programs map to OpenSoul primitives:</p><table tabindex="0"><thead><tr><th>OpenProse concept</th><th>OpenSoul tool</th></tr></thead><tbody><tr><td>Spawn session / Task tool</td><td><code>sessions_spawn</code></td></tr><tr><td>File read/write</td><td><code>read</code> / <code>write</code></td></tr><tr><td>Web fetch</td><td><code>web_fetch</code></td></tr></tbody></table><p>If your tool allowlist blocks these tools, OpenProse programs will fail. See <a href="/docs/tools/skills-config">Skills config</a>.</p><h2 id="security-approvals" tabindex="-1"><a class="header-anchor" href="#security-approvals">#</a> Security + approvals</h2><p>Treat <code>.prose</code> files like code. Review before running. Use OpenSoul tool allowlists and approval gates to control side effects.</p><p>For deterministic, approval-gated workflows, compare with <a href="/docs/tools/lobster">Lobster</a>.</p>`,36)])])}const b=e(l,[["render",r]]);export{h as __pageData,b as default};
